import Foundation

func toSnakeCase(_ str: String) -> String {
    var words: [String] = []
    var current = ""
    for char in str {
        if char.isLetter {
            current.append(char)
        } else if !current.isEmpty {
            words.append(current.lowercased())
            current = ""
        }
    }
    if !current.isEmpty {
        words.append(current.lowercased())
    }
    return words.joined(separator: "_")
}

